diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 6737b50405ee..0c9751b0b19c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -2015,8 +2015,28 @@ Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
       return new ICmpInst(Pred, MaskA,
                           ConstantInt::get(MaskA->getType(), NewComperand));
     }
+  // (icmp eq/ne (and (add X, -1), M), 0) where M = ~(1 << p) and X < 2^(p+1)
+  //    -> (icmp ne/eq (and X, (1 << p) - 1), 0)
+  // For X < 2^(p+1): (X - 1) & ~(2^p) == 0 iff X & (2^p - 1) != 0
+  if (C.isZero() &&
+      match(And, m_c_And(m_OneUse(m_Add(m_Value(A), m_AllOnes())),
+                         m_APInt(Msk)))) {
+    // Check that M has exactly one zero bit (i.e., ~M is a power of 2)
+    APInt InvMsk = ~*Msk;
+    if (InvMsk.isPowerOf2()) {
+      unsigned P = InvMsk.logBase2();
+      // Check that the range of A is within [0, 2^(p+1))
+      ConstantRange CR = computeConstantRange(A, /*ForSigned=*/false);
+      APInt MaxVal = APInt(A->getType()->getScalarSizeInBits(), 1).shl(P + 1);
+      if (CR.getUnsignedMax().ult(MaxVal)) {
+        APInt NewMask = APInt::getLowBitsSet(A->getType()->getScalarSizeInBits(), P);
+        Value *MaskedA = Builder.CreateAnd(A, ConstantInt::get(A->getType(), NewMask));
+        auto NewPred = Pred == CmpInst::ICMP_EQ ? CmpInst::ICMP_NE : CmpInst::ICMP_EQ;
+        return new ICmpInst(NewPred, MaskedA, ConstantInt::getNullValue(MaskedA->getType()));
+      }
+    }
+  }
   }
-
   return nullptr;
 }

